const { spawn } = require('child_process');

return new Promise((resolve) => {
  const diagProcess = spawn('which', ['python3']);
  let pythonPath = '';

  diagProcess.stdout.on('data', (data) => {
    pythonPath += data.toString().trim();
  });

  diagProcess.on('close', () => {
    const scriptPath = '/app/vps-automation-vhck/scripts/fetch_vsd.py';
    const pythonExe = pythonPath || 'python3';
    const pythonProcess = spawn(pythonExe, [scriptPath]);
    let output = '';
    let errorOutput = '';

    pythonProcess.stdout.on('data', (data) => {
      output += data.toString();
    });

    pythonProcess.stderr.on('data', (data) => {
      errorOutput += data.toString();
    });

    pythonProcess.on('close', (code) => {
      if (code !== 0) {
        resolve([{ json: { error: `Script exited with code ${code}`, stderr: errorOutput, status: 'error' } }]);
        return;
      }
      try {
        const lines = output.split('\\n');
        let jsonStr = '';
        let inJson = false;

        for (const line of lines) {
          if (line.startsWith('{')) {
            inJson = true;
          }
          if (inJson) {
            jsonStr += line + '\\n';
          }
        }

        if (!jsonStr.trim()) {
          resolve([{ json: { error: 'No JSON found in output', status: 'error' } }]);
          return;
        }

        const vsdData = JSON.parse(jsonStr);
        resolve([{ json: vsdData }]);
      } catch (e) {
        resolve([{ json: { error: 'Failed to parse JSON output: ' + e.message, status: 'error' } }]);
      }
    });

    pythonProcess.on('error', (error) => {
      resolve([{ json: { error: error.message, pythonPath: pythonPath, status: 'error' } }]);
    });
  });
});

const fs = require('fs');
const input = $input.first().json;
const excelInfo = input.excel_info;
const status = input.status;

if (status !== 'success') {
  return [{ json: { status: 'error', message: input.message || 'Fetch failed', details: input } }];
}

if (!excelInfo || excelInfo.status !== 'success') {
  return [{ json: { status: 'error', message: 'Excel creation failed', details: excelInfo } }];
}

const path = excelInfo.file;

try {
  if (fs.existsSync(path)) {
    const stats = fs.statSync(path);
    return [{ json: { 
      status: 'success', 
      message: `Excel file created: ${excelInfo.message}`,
      file: path, 
      file_size: stats.size,
      records_count: excelInfo.records_count,
      timestamp: excelInfo.timestamp
    } }];
  } else {
    return [{ json: { status: 'error', message: `File not found: ${path}` } }];
  }
} catch (error) {
  return [{ json: { status: 'error', message: error.message } }];
}

const fs = require('fs');

const input = $input.first().json;
if (input.status === 'error') {
  return [{ json: { status: 'error', message: 'Cannot embed: ' + input.message } }];
}

try {
  console.log('📝 Embedding JSON into HTML files...');

  // Find JSON file - try both container and local paths
  let jsonPath = null;
  const jsonPathOptions = [
    '/app/vps-automation-vhck/data/vsd_records.json',
    '/Users/hieudt/vps-automation-vhck/data/vsd_records.json'
  ];

  for (const path of jsonPathOptions) {
    if (fs.existsSync(path)) {
      jsonPath = path;
      console.log('✓ Found JSON at: ' + path);
      break;
    }
  }

  if (!jsonPath) {
    return [{ json: { status: 'error', message: 'JSON file not found at any expected location', tried: jsonPathOptions } }];
  }

  const jsonContent = fs.readFileSync(jsonPath, 'utf-8');
  const jsonData = JSON.parse(jsonContent);
  const recordCount = jsonData.records ? jsonData.records.length : 0;

  // Prepare embedded script
  const jsonStr = JSON.stringify(jsonData, null, 0);
  const embeddedScript = '\\n    <script>\\n      window.EMBEDDED_DATA = ' + jsonStr + ';\\n      console.log("Embedded data loaded: ' + recordCount + ' records");\\n    </script>';

  // Update HTML files in Docker container (/app/ path)
  const htmlFileSets = [
    {
      base: '/app/vps-automation-vhck',
      files: ['docs/index.html', 'index.html', 'web/vps_automation_vhck.html']
    }
  ];

  let successCount = 0;
  const updates = [];

  for (const fileSet of htmlFileSets) {
    for (const relPath of fileSet.files) {
      const htmlPath = fileSet.base + '/' + relPath;

      try {
        if (!fs.existsSync(htmlPath)) {
          console.log('⚠️  File not found: ' + htmlPath);
          updates.push({ file: htmlPath, status: 'not_found' });
          continue;
        }

        let htmlContent = fs.readFileSync(htmlPath, 'utf-8');
        const originalSize = htmlContent.length;

        // Remove old embedded data
        htmlContent = htmlContent.replace(/<script>[\\s\\S]*?window\\.EMBEDDED_DATA[\\s\\S]*?<\\/script>/g, '');

        // Add new embedded data before closing body tag
        htmlContent = htmlContent.replace('</body>', embeddedScript + '\\n</body>');

        // Write updated HTML
        fs.writeFileSync(htmlPath, htmlContent);
        successCount++;
        console.log('✅ Updated: ' + htmlPath + ' (' + originalSize + ' → ' + htmlContent.length + ' bytes)');
        updates.push({ file: htmlPath, status: 'success', size: htmlContent.length });
      } catch (e) {
        console.log('❌ Failed: ' + htmlPath + ' - ' + e.message);
        updates.push({ file: htmlPath, status: 'error', error: e.message });
      }
    }
  }

  return [{ json: {
    status: 'success',
    message: 'Embedded ' + recordCount + ' records into ' + successCount + ' HTML files',
    records_embedded: recordCount,
    files_updated: successCount,
    json_path: jsonPath,
    updates: updates,
    timestamp: new Date().toISOString()
  } }];
} catch (error) {
  return [{ json: {
    status: 'error',
    message: 'Embedding failed: ' + error.message,
    error_stack: error.stack
  } }];
}

const fs = require('fs');
const https = require('https');

const input = $input.first().json;
if (input.status === 'error') {
  return [{ json: { status: 'error', message: 'Cannot commit: ' + input.message } }];
}

let token, owner, repo, baseDir;
try {
  let configPath = null;
  const configPathOptions = [
    '/app/vps-automation-vhck/.github-token.json',
    '/Users/hieudt/vps-automation-vhck/.github-token.json'
  ];

  for (const path of configPathOptions) {
    if (fs.existsSync(path)) {
      configPath = path;
      baseDir = path.substring(0, path.lastIndexOf('/.github'));
      console.log('✓ Found token config at: ' + path);
      break;
    }
  }

  if (!configPath) {
    return [{ json: { status: 'error', message: 'Token config not found', tried: configPathOptions } }];
  }

  const config = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
  token = config.github.token;
  owner = config.github.owner;
  repo = config.github.repo;
} catch (e) {
  return [{ json: { status: 'error', message: 'Token config error: ' + e.message } }];
}

const pushFile = (path, content, message) => {
  return new Promise((resolve, reject) => {
    const url = `/repos/${owner}/${repo}/contents/${path}`;

    const getReq = https.request({
      hostname: 'api.github.com',
      path: url,
      method: 'GET',
      headers: {
        'Authorization': `token ${token}`,
        'Accept': 'application/vnd.github.v3+json',
        'User-Agent': 'n8n'
      }
    }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        let sha = '';
        try {
          sha = JSON.parse(data).sha || '';
        } catch (e) {}

        const body = JSON.stringify({
          message: message,
          content: content,
          sha: sha,
          branch: 'main'
        });

        const putReq = https.request({
          hostname: 'api.github.com',
          path: url,
          method: 'PUT',
          headers: {
            'Authorization': `token ${token}`,
            'Accept': 'application/vnd.github.v3+json',
            'Content-Type': 'application/json',
            'Content-Length': body.length,
            'User-Agent': 'n8n'
          }
        }, (res) => {
          let respData = '';
          res.on('data', chunk => respData += chunk);
          res.on('end', () => {
            if (res.statusCode >= 400) {
              reject(new Error(`GitHub API ${res.statusCode}`));
            } else {
              resolve(res.statusCode);
            }
          });
        });

        putReq.on('error', reject);
        putReq.write(body);
        putReq.end();
      });
    });

    getReq.on('error', reject);
    getReq.end();
  });
};

return new Promise(async (resolve) => {
  try {
    // Find JSON file (read from /app/ in container)
    let jsonPath = null;
    const jsonPathOptions = [
      '/app/vps-automation-vhck/data/vsd_records.json'
    ];

    for (const path of jsonPathOptions) {
      if (fs.existsSync(path)) {
        jsonPath = path;
        console.log('✓ Found JSON at: ' + path);
        break;
      }
    }

    if (!jsonPath) {
      return resolve([{ json: { status: 'error', message: 'JSON file not found', tried: jsonPathOptions } }]);
    }

    const recordCount = input.records_embedded || 0;
    const filesUpdated = input.files_updated || 0;

    console.log('📤 Committing files to GitHub...');

    // Commit JSON first
    const jsonContent = fs.readFileSync(jsonPath, 'utf-8');
    const jsonBase64 = Buffer.from(jsonContent).toString('base64');
    await pushFile('data/vsd_records.json', jsonBase64, 'ci: update VSD data (' + recordCount + ' records)');
    console.log('✅ Committed JSON');

    // Commit all 3 HTML files with embedded data
    const htmlFiles = [
      'docs/index.html',
      'index.html',
      'web/vps_automation_vhck.html'
    ];

    for (const htmlRelPath of htmlFiles) {
      try {
        const fullPath = baseDir + '/' + htmlRelPath;
        const htmlContent = fs.readFileSync(fullPath, 'utf-8');
        const htmlBase64 = Buffer.from(htmlContent).toString('base64');
        await pushFile(htmlRelPath, htmlBase64, 'ci: update HTML with embedded data (' + recordCount + ' records)');
        console.log('✅ Committed ' + htmlRelPath);
      } catch (e) {
        console.log('⚠️  Skipped ' + htmlRelPath + ': ' + e.message);
      }
    }

    resolve([{ json: {
      status: 'success',
      message: 'Committed ' + recordCount + ' records to GitHub (' + filesUpdated + ' HTML files updated)',
      github_url: 'https://github.com/' + owner + '/' + repo,
      pages_url: 'https://' + owner + '.github.io/' + repo + '/',
      records_committed: recordCount,
      files_updated: filesUpdated,
      timestamp: new Date().toISOString()
    } }]);
  } catch (error) {
    console.error('❌ Commit failed:', error.message);
    resolve([{ json: {
      status: 'error',
      message: 'Commit failed: ' + error.message
    } }]);
  }
});

const input = $input.first().json;

if (input.status === 'error') {
  return [{ json: {
    status: 'error',
    message: 'Workflow failed: ' + input.message,
    error_details: input,
    timestamp: new Date().toISOString()
  } }];
}

return [{ json: {
  status: 'success',
  message: 'Workflow completed! Data committed to GitHub',
  github_url: input.github_url,
  pages_url: input.pages_url,
  records_committed: input.records_committed || 0,
  timestamp: new Date().toISOString()
} }];
